# Numerical label to text label for visualization
def read_txt_to_dict(file_path):
    my_dict = {}
    with open(file_path, 'r', encoding='utf-8') as file:
        for line in file:
            line = line.strip()
            line = line.strip('{')
            line = line.strip('}')
            if line:
                key_value = line.split(': ', 1)
                key = int(key_value[0])
                value = key_value[1].strip().rstrip(",").strip("'")
                my_dict[key] = value
    return my_dict

